// 급식 레시피 시드 데이터 (gzip+base64 압축, 로드 시 자동 해제)
(async () => {
  try {
    const b64 = "";
    const bytes = Uint8Array.from(atob(b64), c => c.charCodeAt(0));
    const stream = new Blob([bytes]).stream().pipeThrough(new DecompressionStream('gzip'));
    const buf = await new Response(stream).arrayBuffer();
    window.SEED = JSON.parse(new TextDecoder().decode(buf));
    window.dispatchEvent(new Event('seed-ready'));
  } catch (e) { console.warn('시드 데이터 로드 실패:', e); }
})();
